// Handler creates http.Handler with routing matching OpenAPI spec.
func Handler(si ServerInterface) http.Handler {
	return HandlerWithOptions(si, StdHTTPServerOptions{})
}

// ServeMux is an abstraction of http.ServeMux.
type ServeMux interface {
	HandleFunc(pattern string, handler func(http.ResponseWriter, *http.Request))
	ServeHTTP(w http.ResponseWriter, r *http.Request)
}

type StdHTTPServerOptions struct {
	BaseURL          string
	BaseRouter       ServeMux
	Middlewares      []MiddlewareFunc
	ErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

// HandlerFromMux creates http.Handler with routing matching OpenAPI spec based on the provided mux.
func HandlerFromMux(si ServerInterface, m ServeMux) http.Handler {
	return HandlerWithOptions(si, StdHTTPServerOptions{
		BaseRouter: m,
	})
}

func HandlerFromMuxWithBaseURL(si ServerInterface, m ServeMux, baseURL string) http.Handler {
	return HandlerWithOptions(si, StdHTTPServerOptions{
		BaseURL:    baseURL,
		BaseRouter: m,
	})
}

// HandlerWithOptions creates http.Handler with additional options
func HandlerWithOptions(si ServerInterface, options StdHTTPServerOptions) http.Handler {
	m := options.BaseRouter

	if m == nil {
		m = http.NewServeMux()
	}
	if options.ErrorHandlerFunc == nil {
		options.ErrorHandlerFunc = func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		}
	}

	wrapper := ServerInterfaceWrapper{
		Handler:            si,
		HandlerMiddlewares: options.Middlewares,
		ErrorHandlerFunc:   options.ErrorHandlerFunc,
	}

	m.HandleFunc("GET "+options.BaseURL+"/audit/logs", wrapper.GetAuditLogs)
	m.HandleFunc("POST "+options.BaseURL+"/audit/logs/cleanup", wrapper.PostAuditLogsCleanup)
	m.HandleFunc("GET "+options.BaseURL+"/auth/sessions", wrapper.GetAuthSessions)
	m.HandleFunc("DELETE "+options.BaseURL+"/auth/sessions/{id}", wrapper.DeleteAuthSessionsId)
	m.HandleFunc("GET "+options.BaseURL+"/dns/domains", wrapper.GetDnsDomains)
	m.HandleFunc("POST "+options.BaseURL+"/dns/domains", wrapper.PostDnsDomains)
	m.HandleFunc("DELETE "+options.BaseURL+"/dns/domains/{id}", wrapper.DeleteDnsDomainsId)
	m.HandleFunc("PUT "+options.BaseURL+"/dns/domains/{id}", wrapper.PutDnsDomainsId)
	m.HandleFunc("GET "+options.BaseURL+"/dns/export", wrapper.GetDnsExport)
	m.HandleFunc("GET "+options.BaseURL+"/dns/records", wrapper.GetDnsRecords)
	m.HandleFunc("POST "+options.BaseURL+"/dns/records", wrapper.PostDnsRecords)
	m.HandleFunc("DELETE "+options.BaseURL+"/dns/records/{id}", wrapper.DeleteDnsRecordsId)
	m.HandleFunc("PUT "+options.BaseURL+"/dns/records/{id}", wrapper.PutDnsRecordsId)
	m.HandleFunc("GET "+options.BaseURL+"/info", wrapper.GetInfo)
	m.HandleFunc("POST "+options.BaseURL+"/login", wrapper.PostLogin)
	m.HandleFunc("POST "+options.BaseURL+"/logout", wrapper.PostLogout)
	m.HandleFunc("GET "+options.BaseURL+"/rbac/resources/suggest", wrapper.GetRbacResourcesSuggest)
	m.HandleFunc("GET "+options.BaseURL+"/rbac/rolebindings", wrapper.GetRbacRolebindings)
	m.HandleFunc("POST "+options.BaseURL+"/rbac/rolebindings", wrapper.PostRbacRolebindings)
	m.HandleFunc("DELETE "+options.BaseURL+"/rbac/rolebindings/{id}", wrapper.DeleteRbacRolebindingsId)
	m.HandleFunc("PUT "+options.BaseURL+"/rbac/rolebindings/{id}", wrapper.PutRbacRolebindingsId)
	m.HandleFunc("GET "+options.BaseURL+"/rbac/roles", wrapper.GetRbacRoles)
	m.HandleFunc("POST "+options.BaseURL+"/rbac/roles", wrapper.PostRbacRoles)
	m.HandleFunc("DELETE "+options.BaseURL+"/rbac/roles/{id}", wrapper.DeleteRbacRolesId)
	m.HandleFunc("PUT "+options.BaseURL+"/rbac/roles/{id}", wrapper.PutRbacRolesId)
	m.HandleFunc("GET "+options.BaseURL+"/rbac/serviceaccounts", wrapper.GetRbacServiceaccounts)
	m.HandleFunc("POST "+options.BaseURL+"/rbac/serviceaccounts", wrapper.PostRbacServiceaccounts)
	m.HandleFunc("DELETE "+options.BaseURL+"/rbac/serviceaccounts/{id}", wrapper.DeleteRbacServiceaccountsId)
	m.HandleFunc("PUT "+options.BaseURL+"/rbac/serviceaccounts/{id}", wrapper.PutRbacServiceaccountsId)
	m.HandleFunc("POST "+options.BaseURL+"/rbac/serviceaccounts/{id}/reset", wrapper.PostRbacServiceaccountsIdReset)
	m.HandleFunc("POST "+options.BaseURL+"/rbac/simulate", wrapper.PostRbacSimulate)
	m.HandleFunc("GET "+options.BaseURL+"/rbac/verbs/suggest", wrapper.GetRbacVerbsSuggest)

	return m
}
